<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setCorner</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Qt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::TopLeftCorner, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Qt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::LeftDockWidgetArea);</span></span>
